var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"메리 크리스마스 선생님.","JPN":" メリークリスマス、先生。","ENG":"Merry Christmas, Teacher.","TWN":"老師，聖誕節快樂。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 메리 크리스마스.","JPN":" ああ。メリークリスマス。","ENG":"Yes. Merry Christmas.","TWN":"聖誕節快樂。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"후훗. 역시 목소리 들으니까 정말 좋아요.","JPN":" ふふっ。やっぱり声が聞けるととても嬉しいですね。","ENG":"Fu fuu. It's good to hear your voice.","TWN":"呵呵，聽到老師的聲音真開心。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한두번 들어본 것도 아니면서.","JPN":" そんなに疎遠ではないと思っているんだが。","ENG":"Well, you've heard it more times than I can count.","TWN":"又不是第一次聽到。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오늘 큰 행사라도 한 것 같던데, 준비하느라 고생 많았겠어.","JPN":" 今日は大きなイベントもあったみたいだし、準備ご苦労様。","ENG":"I heard you had a big event today. Great job with the preparations.","TWN":"今天是辦大型活動嗎？應該準備得很辛苦吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"아이들이 고생해 줬죠. 전 즐기기만 한 걸요.","JPN":" 子どもたちが頑張ってくれましたから。私はただ楽しんだだけです。","ENG":"You should say that to the kids. All I did was enjoy it.","TWN":"辛苦的都是學生，我是玩得很開心。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"TV 보셨나요? 오늘 저희 학생들의 마술공연이 생중계되었어요.","JPN":" TVをご覧になりましたか？　今日うちの学生のマジックショーが生中継されたんですよ。","ENG":"Did you see what was on TV? Our students' magic performance was broadcast on live television.","TWN":"老師有看到新聞嗎？有現場直播我們的學生變魔術呢。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"어찌나 사랑스럽던지…","JPN":" すごく愛くるしかったです……","ENG":"How adorable it was...","TWN":"真是可愛…"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 산타와 루돌프 복장을 하고 있던 학생들 말하는 거지?","JPN":" そうだね。サンタとルドルフの格好をしてた子たちだろう？","ENG":"I did. You're talking about the students in the Santa and Rudolph costumes, right?","TWN":"有，你是說那二個打扮成聖誕老公公和魯道夫的學生吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"훌륭한 학생들이야. 앞으로의 장래가 정말 기대돼.","JPN":" 二人とも素晴らしい学生だね。これからの将来が楽しみだ。 ","ENG":"What an exemplary role model they are. I look forward to what their future holds.","TWN":"很優秀的學生，我很期待她們的將來。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"쉬지말고 움직여라! 곧 아침이 다가올 거다!!","JPN":"休まずに動け！　もうすぐ朝が来る！","ENG":"No time for rest! The sun will be out anytime now!","TWN":"不准停，繼續跑！天就快亮了！！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"으허헝…! 허리 부러질 거 같아… 이제 그만 하라고!","JPN":"うううっ……！　腰が折れそう……もうやめて！","ENG":"Waah...! My back is gonna break... Will you quit it now?!","TWN":"嗚嗚嗚…！我的腰快斷了…你到底夠了沒！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"이런… 아이들이 너무 뒤풀이를 즐기는 것 같네요. 조금 주의를 줘야 할까…","JPN":" あら……あの子たちったら打ち上げではしゃぎすぎみたいです。少し注意すべきですかね……","ENG":"Oh, dear... I think the children are enjoying the afterparty a little too much. I should go give them a warning...","TWN":"真是的…學生們玩得太瘋了，我請她們注意…"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 학생들이란 원래 그런 거잖아.","JPN":" 大丈夫だ。学生時代はみんなそんなものだよ。","ENG":"It's all right. Students will be students, no?","TWN":"沒事，學生本來就是這樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 오랜만에… 멀리서나마 아이들 목소리를 듣게 돼서 좋고.","JPN":" そのおかげで久しぶりに……遠くからでも子どもたちの声を聞くことができた。","ENG":"It's nice... to hear their voices, even if I'm far away.","TWN":"我也很久…沒聽到她們的聲音了。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"후훗. 그렇고 말고요.","JPN":" ふふっ。そうですね。","ENG":"Fu fuu. Of course it is.","TWN":"呵呵，也是。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"오늘 같은 날이 아니면 언제 아이들 얼굴을 보겠어요?","JPN":" こんなことでもないと子どもたちの顔を見る機会もなかなかありませんからね。 ","ENG":"If not on a day like this, I won't be able to see their happy faces that often.","TWN":"也只有像今天這種日子，才有機會看到大家不是嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇겠지… 이사장의 업무는 많이 바쁠 테니까.","JPN":" そうだな……理事長の仕事はとても忙しいだろうから。 ","ENG":"You're right... Being Chairwoman means you're busy with work.","TWN":"沒錯…理事長應該也很忙吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"그래도 교육자가 되기로 한 걸 후회한 적은 없어요.","JPN":" でも私は教育者になったことを後悔したことはありません。","ENG":"But I don't regret becoming an educator.","TWN":"但我不後悔成為一名教育家。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"학생들이 강해지는 모습을 보는 것도 저에게 있어선 최고의 보람이기도 한 걸요.","JPN":" 学生たちが強くなっていく姿を見守るのも、私にとっては大きなやりがいを感じる仕事の一つなんです。","ENG":"Seeing the students become stronger is the best reward I could ask for.","TWN":"看到學生變強，就是我最大的滿足。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"오늘만큼은 카운터임을 떠나서 모두 즐거운 하루를 보냈으면 좋겠네요.","JPN":" 今日ぐらいはカウンターの立場から離れて、みんなには楽しい一日を過ごしてほしいと思っています。","ENG":"I just wish they would enjoy today without being reminded that they are Counters.","TWN":"希望大家今天都能脫離制裁者的框架，好好地玩一玩。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"너무 지나쳐요 미카! 이제 그만 진정해요!","JPN":"やりすぎですよ、ミカさん！　もう落ち着いてください！","ENG":"You have gone too far, Mika! Calm yourself down!","TWN":"米卡，你太過頭了！快冷靜下來！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"와하하! 불이다 불!","JPN":"わはは！　火だ、火！","ENG":"Wahaha! It's fire! FIRE!","TWN":"哇哈哈！有火欸！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EXPLOSION_ATTACK_BIG"},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"어머나… 죄송하지만 이만 끊어야 할 것 같아요. 아이들이 너무 소란스럽네요.","JPN":" あら……すいません、もう切らないといけないみたいです。子どもたちが羽目を外しすぎているみたいで。","ENG":"Oh, dear... I'm sorry, but I think I have to go. The children are getting too rowdy.","TWN":"哎呀…老師抱歉，我要先掛斷了，她們好像玩得有點太過頭。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"역시 주의를 줘야 할 것 같아요. 너무 제멋대로 하게 두는 것도 좋지 않겠어요.","JPN":" やっぱり注意した方がよさそうです。最低限節度は守ってもらわないと。","ENG":"I need to give them a stern warning. After all, it's not good to let them do whatever they want.","TWN":"我果然還是得盯著才行，不能太放任她們。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……어쩔 수 없군. 그럼 나중에 또 연락할게.","JPN":" ……仕方ないな。それではまた連絡するよ。","ENG":"...I see. Then let's talk again later.","TWN":"……沒辦法，那就下次再連絡囉。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"네. 그래도 가끔은 직접 찾아와 주세요.","JPN":" はい。でもたまにはアカデミーにもいらしてください。","ENG":"Yes. And please try to come by sometime.","TWN":"好，偶爾也親自來看看我們吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_MAGICIAN_NPC_NULL","text":{"KOREA":"그 때는 좀 더… 느긋하게 이야기 나눠봐요.","JPN":" その時はもうちょっと……落ち着いてお話しできるといいんですが。","ENG":"When you do... we'll have a leisurely conversation.","TWN":"到時候…再好好聊聊。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_MAGICIAN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};